(()=>{var e,t={1923:(e,t,n)=>{n(3358),n(8563),n(6313);var o=n(7255),r=(n(4592),n(8149),[{element:"div",className:"aboutDivCenter",children:[{element:"h1",textContent:"RR+ Dev Log – Real Talk",style:{fontSize:"2em",marginBottom:"0.5em",textAlign:"center"},children:[]},{element:"p",textContent:"Random Rants + development is slowing down... or maybe frozen. The IDE (online code editor) struggle is real, and unblocked options are basically extinct.",style:{fontWeight:"bold",fontSize:"1.1em",marginBottom:"1em",color:"#000"},children:[]},{element:"p",textContent:"This whole thing runs on free containers, zero funding, and vibes. Which means I rely on platforms that don’t lock me out after 10 minutes.",children:[]},{element:"p",textContent:"RR and RR+ were born on Glitch.com. It was fast, free, and — most importantly — unblocked at school. It let me ship updates from the back of the classroom.",children:[]},{element:"p",textContent:"Yeah, I got grounded a lot. Yeah, I pushed updates instead of doing classwork. But RR+ was my escape in code — loud chats, soundboards, alt chaos.",children:[]},{element:"p",textContent:"Then Glitch died. I jumped to CodeSandbox. But I hit limits instantly. Their free tier is strict — like timer-based strict. Not gonna work.",children:[]},{element:"p",textContent:"Yeah, most online IDEs *do* work — for like 3 days. Then boom: outta credits, outta runtime, outta luck. Dev freezes mid-feature. Everything's fine until it's not."},{element:"p",textContent:"Yes, I have a legit Windows PC. Yes, it’s way better for dev. No, I can’t use it — it’s locked up because I’m grounded. So RR+ development = surviving on school Chromebooks and free IDEs until further notice."},{element:"p",textContent:"Until I find a better option, RR+ updates will be rare or totally paused. The site still works. Chat still runs. Soundboard still slaps. But dev? On hold.",children:[]},{element:"p",textContent:"Bonus pain: lost access to a bunch of dev accounts. 2FA + getting grounded = rip GitHub logins. So if stuff breaks randomly, that’s why.",children:[]},{element:"p",textContent:"This project isn’t dead. It’s just cornered. If I find a way back in — or something new gets unblocked — we’re back.",children:[]}]}]),s=o.createElementsFromJSON(r);o.appendElements(o.body,s)}},n={};function o(e){var r=n[e];if(void 0!==r)return r.exports;var s=n[e]={exports:{}};return t[e](s,s.exports,o),s.exports}o.m=t,e=[],o.O=(t,n,r,s)=>{if(!n){var i=1/0;for(c=0;c<e.length;c++){for(var[n,r,s]=e[c],a=!0,l=0;l<n.length;l++)(!1&s||i>=s)&&Object.keys(o.O).every((e=>o.O[e](n[l])))?n.splice(l--,1):(a=!1,s<i&&(i=s));if(a){e.splice(c--,1);var d=r();void 0!==d&&(t=d)}}return t}s=s||0;for(var c=e.length;c>0&&e[c-1][2]>s;c--)e[c]=e[c-1];e[c]=[n,r,s]},o.o=(e,t)=>Object.prototype.hasOwnProperty.call(e,t),(()=>{var e={371:0};o.O.j=t=>0===e[t];var t=(t,n)=>{var r,s,[i,a,l]=n,d=0;if(i.some((t=>0!==e[t]))){for(r in a)o.o(a,r)&&(o.m[r]=a[r]);if(l)var c=l(o)}for(t&&t(n);d<i.length;d++)s=i[d],o.o(e,s)&&e[s]&&e[s][0](),e[s]=0;return o.O(c)},n=self.webpackChunkrandomrants_plus=self.webpackChunkrandomrants_plus||[];n.forEach(t.bind(null,0)),n.push=t.bind(null,n.push.bind(n))})();var r=o.O(void 0,[804],(()=>o(1923)));r=o.O(r)})();